  // Submit an offer on a listing
  app.post("/api/marketplace/:id/offer", requireAuth, demoGuard, async (req: Request, res: Response) => {
    try {
      const listingId = parseInt(req.params.id);
      const buyerUserId = req.session.userId!;
      const item = await storage.getMarketplaceItem(listingId);
      if (!item) return res.status(404).json({ message: "Listing not found" });
      if (!item.makeOfferEnabled) return res.status(400).json({ message: "This listing is firm price" });
      if (item.sellerId === buyerUserId) return res.status(400).json({ message: "Cannot offer on your own listing" });
      if (!["available", "active", "pending"].includes(item.status || "available")) return res.status(400).json({ message: "Listing is not available" });
      const isBackupOffer = item.status === "pending";

      const { offerAmount, message } = req.body;
      if (!offerAmount || offerAmount <= 0) return res.status(400).json({ message: "Invalid offer amount" });

      const existing = await storage.getMarketplaceOfferByBuyer(listingId, buyerUserId);
      if (existing && ["pending", "countered"].includes(existing.status || "")) {
        return res.status(400).json({ message: "You already have an active offer on this listing" });
      }
      if (existing && (existing.offerActionCount || 0) >= 4) {
        return res.status(400).json({ message: "You have reached the 4-action offer limit for this listing" });
      }

      // Check against hidden minimum threshold
      if (item.minOfferThreshold && offerAmount < item.minOfferThreshold) {
        const filtered = await storage.createMarketplaceOffer({
          listingId,
          buyerUserId,
          sellerUserId: item.sellerId,
          offerAmount,
          status: "filtered",
          message,
          offerActionCount: 1,
        });
        return res.json({ offer: filtered, filtered: true, message: "This offer is below the seller's acceptable range." });
      }

      // 20-minute response window per exchange
      const expiresAt = new Date(Date.now() + 20 * 60 * 1000);

      const actionCount = existing ? (existing.offerActionCount || 0) + 1 : 1;
      const offer = await storage.createMarketplaceOffer({
        listingId,
        buyerUserId,
        sellerUserId: item.sellerId,
        offerAmount,
        status: "pending",
        message,
        offerActionCount: actionCount,
        expiresAt,
      });

      // Notify seller
      await storage.createNotification({
        userId: item.sellerId,
        title: isBackupOffer ? "New Backup Offer Received" : "New Offer Received",
        body: isBackupOffer
          ? `Someone submitted a backup offer of $${offerAmount.toLocaleString()} on "${item.title}" while it's pending. You'll see it if the current deal falls through.`
          : `Someone offered $${offerAmount.toLocaleString()} on your listing: ${item.title}`,
        type: "marketplace",
        jobId: null,
      });

      res.json({ offer, filtered: false, isBackupOffer });
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  // Get offers for a listing (seller view)
  app.get("/api/marketplace/:id/offers", requireAuth, async (req: Request, res: Response) => {
    try {
      const listingId = parseInt(req.params.id);
      const item = await storage.getMarketplaceItem(listingId);
      if (!item) return res.status(404).json({ message: "Listing not found" });
      const userId = req.session.userId!;
      // Sellers see all offers; buyers see only their own
      if (item.sellerId === userId) {
        const offers = await storage.getMarketplaceOffersByListing(listingId);
        return res.json(offers);
      }
      // Buyer: return their own offer only
      const myOffer = await storage.getMarketplaceOfferByBuyer(listingId, userId);
      return res.json(myOffer ? [myOffer] : []);
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  // Respond to an offer (seller: accept/decline/counter)
  app.patch("/api/marketplace/offers/:offerId", requireAuth, async (req: Request, res: Response) => {
    try {
      const offerId = parseInt(req.params.offerId);
      const offer = await storage.getMarketplaceOffer(offerId);
      if (!offer) return res.status(404).json({ message: "Offer not found" });
      const item = await storage.getMarketplaceItem(offer.listingId);
      if (!item) return res.status(404).json({ message: "Listing not found" });

      const userId = req.session.userId!;
      const isSeller = item.sellerId === userId;
      const isBuyer = offer.buyerUserId === userId;
      if (!isSeller && !isBuyer) return res.status(403).json({ message: "Unauthorized" });

      const { action, counterAmount } = req.body;

      const currentCount = offer.offerActionCount || 1;

      if (isSeller) {
        if (action === "accept") {
          await storage.updateMarketplaceOffer(offerId, { status: "accepted", sellerRespondedAt: new Date() });
          await storage.updateMarketplaceItem(item.id, { status: "pending" });
          const sellerForAccept = await storage.getUser(item.sellerId);
          if (sellerForAccept) await storage.updateUser(item.sellerId, { mktAcceptedOffers: (sellerForAccept.mktAcceptedOffers || 0) + 1 });
          // Auto-create deal and unlock chat
          const deal = await storage.createMarketplaceDeal({
            listingId: item.id,
            offerId,
            buyerUserId: offer.buyerUserId,
            sellerUserId: item.sellerId,
            agreedPrice: offer.offerAmount,
            status: "pending_completion",
          });
          // Increment deal totals for both users
          await storage.updateUser(item.sellerId, { mktDealsAsSellerTotal: (await storage.getUser(item.sellerId))!.mktDealsAsSellerTotal! + 1 });
          await storage.updateUser(offer.buyerUserId, { mktDealsAsBuyerTotal: (await storage.getUser(offer.buyerUserId))!.mktDealsAsBuyerTotal! + 1 });
          await storage.createNotification({
            userId: offer.buyerUserId,
            title: "Offer Accepted — Deal Created",
            body: `Your offer of $${offer.offerAmount.toLocaleString()} on "${item.title}" was accepted. In-app chat is now unlocked.`,
            type: "marketplace",
            jobId: null,
          });
          return res.json({ offer: await storage.getMarketplaceOffer(offerId), deal });
        } else if (action === "decline") {
          await storage.updateMarketplaceOffer(offerId, { status: "declined", sellerRespondedAt: new Date() });
          await storage.createNotification({
            userId: offer.buyerUserId,
            title: "Offer Declined",
            body: `Your offer on "${item.title}" was declined.`,
            type: "marketplace",
            jobId: null,
          });
        } else if (action === "counter" && counterAmount) {
          if (currentCount >= 3) {
            return res.status(400).json({ message: "Maximum counter offers reached. Only accept or decline is allowed." });
          }
          await storage.updateMarketplaceOffer(offerId, {
            status: "countered",
            counterAmount,
            offerActionCount: currentCount + 1,
            sellerRespondedAt: new Date(),
            expiresAt: new Date(Date.now() + 20 * 60 * 1000),
          });
          const sellerForCounter = await storage.getUser(item.sellerId);
          if (sellerForCounter) await storage.updateUser(item.sellerId, { mktCounterOffers: (sellerForCounter.mktCounterOffers || 0) + 1 });
          await storage.createNotification({
            userId: offer.buyerUserId,
            title: "Counter Offer Received",
            body: `The seller countered your offer with $${counterAmount.toLocaleString()} on "${item.title}"`,
            type: "marketplace",
            jobId: null,
          });
        }
      } else if (isBuyer) {
        if (action === "accept_counter" && offer.status === "countered") {
          await storage.updateMarketplaceOffer(offerId, { status: "accepted", buyerRespondedAt: new Date() });
          await storage.updateMarketplaceItem(item.id, { status: "pending" });
          // Auto-create deal and unlock chat
          const agreedPrice = offer.counterAmount ?? offer.offerAmount;
          const deal = await storage.createMarketplaceDeal({
            listingId: item.id,
            offerId,
            buyerUserId: offer.buyerUserId,
            sellerUserId: item.sellerId,
            agreedPrice,
            status: "pending_completion",
          });
          await storage.updateUser(item.sellerId, { mktDealsAsSellerTotal: (await storage.getUser(item.sellerId))!.mktDealsAsSellerTotal! + 1 });
          await storage.updateUser(offer.buyerUserId, { mktDealsAsBuyerTotal: (await storage.getUser(offer.buyerUserId))!.mktDealsAsBuyerTotal! + 1 });
          await storage.createNotification({
            userId: item.sellerId,
            title: "Counter Offer Accepted — Deal Created",
            body: `Buyer accepted your counter of $${agreedPrice.toLocaleString()} on "${item.title}". In-app chat is now unlocked.`,
            type: "marketplace",
            jobId: null,
          });
          return res.json({ offer: await storage.getMarketplaceOffer(offerId), deal });
        } else if (action === "counter_back" && offer.status === "countered" && counterAmount) {
          if (currentCount >= 3) {
            return res.status(400).json({ message: "Maximum counter offers reached. Only accept or decline is allowed." });
          }
          await storage.updateMarketplaceOffer(offerId, {
            status: "countered",
            offerAmount: counterAmount,
            offerActionCount: currentCount + 1,
            buyerRespondedAt: new Date(),
            expiresAt: new Date(Date.now() + 20 * 60 * 1000),
          });
          await storage.createNotification({
            userId: item.sellerId,
            title: "Buyer Counter Offer",
            body: `Buyer counter-offered $${counterAmount.toLocaleString()} on "${item.title}"`,
            type: "marketplace",
            jobId: null,
          });
        } else if (action === "decline_counter") {
          await storage.updateMarketplaceOffer(offerId, { status: "declined", buyerRespondedAt: new Date() });
        }
      }

      const updated = await storage.getMarketplaceOffer(offerId);
      res.json(updated);
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

