  app.get("/api/studio/tiers", studioTiersHandler);

  app.post("/api/stripe/studio-subscription-checkout", requireAuth, async (req: Request, res: Response) => {
    try {
      const tierId = String(req.body?.tier || "") as StudioTierPlanId;
      const plan = STUDIO_TIER_PLANS[tierId];
      if (!plan) return res.status(400).json({ message: "Invalid tier" });

      const user = await storage.getUser(req.session.userId!);
      if (!user) return res.status(401).json({ message: "User not found" });

      // Hard-block creating a parallel Studio subscription. We only allow a
      // new checkout once the prior subscription has been fully ended by
      // Stripe (customer.subscription.deleted clears studioSubscriptionId).
      // Cancel-at-period-end alone is NOT enough — the user still has paid
      // access to the prior plan until Stripe fires deletion.
      if (user.studioSubscriptionId) {
        if (user.studioTier === tierId && !user.studioSubscriptionCancelAtPeriodEnd) {
          return res.status(400).json({ message: `You're already on the ${plan.label} plan.` });
        }
        return res.status(400).json({
          message: `You already have a Studio subscription. Wait until your current billing period ends before starting a new one.`,
        });
      }

      const host = req.get("host") || "localhost:5000";
      const protocol = req.get("x-forwarded-proto") || "http";
      const baseUrl = `${protocol}://${host}`;

      const stripeSession = await stripeMain.checkout.sessions.create({
        payment_method_types: ["card"],
        customer_email: user.email,
        mode: "subscription",
        line_items: [{
          price_data: {
            currency: "usd",
            product_data: {
              name: plan.productName,
              description: plan.description,
            },
            unit_amount: plan.priceCents,
            recurring: { interval: "month" },
          },
          quantity: 1,
        }],
        success_url: `${baseUrl}/studio?subscription=success`,
        cancel_url: `${baseUrl}/studio?subscription=cancel`,
        subscription_data: {
          metadata: {
            userId: String(user.id),
            userEmail: user.email,
            type: "studio_subscription",
            tier: tierId,
            monthlyCredits: String(plan.monthlyCredits),
          },
        },
        metadata: {
          userId: String(user.id),
          userEmail: user.email,
          type: "studio_subscription",
          tier: tierId,
          monthlyCredits: String(plan.monthlyCredits),
        },
      });

      res.json({ checkoutUrl: stripeSession.url });
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  app.post("/api/stripe/cancel-studio-subscription", requireAuth, async (req: Request, res: Response) => {
    try {
      const user = await storage.getUser(req.session.userId!);
      if (!user) return res.status(401).json({ message: "User not found" });
      if (!user.studioSubscriptionId) {
        return res.status(400).json({ message: "No active Studio subscription." });
      }

      // Period-end cancellation: keep access through the paid period, then
      // Stripe fires customer.subscription.deleted which downgrades the tier
      // back to standard. Matches the UI copy ("reverts when the current
      // period ends") and avoids refund disputes from immediate revocation.
      try {
        await stripeMain.subscriptions.update(user.studioSubscriptionId, {
          cancel_at_period_end: true,
        });
      } catch (cancelErr: any) {
        if (cancelErr?.statusCode === 404 || cancelErr?.raw?.code === "resource_missing") {
          await stripe.subscriptions.update(user.studioSubscriptionId, {
            cancel_at_period_end: true,
          });
        } else {
          throw cancelErr;
        }
      }

      // Flag the cancel-at-period-end so the UI can show the right banner.
      // We deliberately do NOT change studioSubscriptionStatus or clear the
      // subscription id — the user keeps full tier access until Stripe fires
      // customer.subscription.deleted, which downgrades the tier and clears
      // the id atomically. This also prevents parallel-subscription stacking.
      await storage.updateUser(user.id, {
        studioSubscriptionCancelAtPeriodEnd: true,
      });
      await storage.createAuditLog({
        userId: user.id,
        action: "studio_subscription_cancelled",
        details: `Studio ${user.studioTier} subscription set to cancel at period end. Sub: ${user.studioSubscriptionId}`,
      });
      res.json({ message: "Studio subscription will end at the close of the current billing period." });
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  // ── Apple External Purchase Link — mobile checkout bridge ─────────────────
  // On iOS builds, all digital purchases must either use Apple IAP or go
  // through Apple's External Purchase Link entitlement (EU / reader-app path).
  // These two endpoints implement the signed-token bridge:
  //
  //   1. POST /api/mobile/checkout-link  (requires session auth)
  //      Authenticated in-app call. Signs a 15-min HMAC token containing
  //      {userId, product, options} and returns a guberapp.app redirect URL.
  //      The app opens this URL via SFSafariViewController / Browser.open
  //      AFTER showing Apple's mandated external-purchase disclosure sheet.
  //
  //   2. GET  /api/mobile/checkout-redirect  (token-authenticated, no session)
  //      Validates the token, creates the correct Stripe Checkout Session on
  //      behalf of the identified user, then 302-redirects to the Stripe URL.
  //      The user never has to log in to the web — the JWT carries the auth.

  app.post("/api/mobile/checkout-link", requireAuth, async (req: Request, res: Response) => {
    try {
      const { product, options = {} } = req.body;
      if (!product || !isValidProduct(product)) {
        return res.status(400).json({ message: "Invalid product" });
      }
      const userId = req.session.userId!;
      const token = signMobileCheckoutToken(userId, product, options as Record<string, string>);
      const appUrl = process.env.APP_URL || "https://guberapp.app";
      const url = `${appUrl}/mobile-checkout?token=${encodeURIComponent(token)}`;
      res.json({ url });
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  // Validate a caller-supplied success URL against an allowlist so it can be
  // forwarded to Stripe safely. Accepts:
  //   guber://<anything>            — custom-scheme deep links (iOS/Android)
  //   https://guberapp.app/<path>   — universal links on the app domain
  // Anything else is rejected and the provided fallback is returned instead.
  function resolveSuccessUrl(requested: string | undefined, fallback: string): string {
    if (!requested) return fallback;
    try {
      const u = new URL(requested);
      if (u.protocol === "guber:") return requested;
      if (u.protocol === "https:" && u.hostname === "guberapp.app") return requested;
    } catch {}
    return fallback;
  }

  app.get("/api/mobile/checkout-redirect", async (req: Request, res: Response) => {
    const APP_BASE = process.env.APP_URL || "https://guberapp.app";
    const raw = String(req.query.token || "");
    const payload = verifyMobileCheckoutToken(raw);
    if (!payload) {
      // Token is missing, expired, or tampered. Return 401 so the native app
      // SDK can detect the failure programmatically and prompt the user to retry.
      return res.status(401).json({ message: "Checkout link has expired or is invalid. Please try again." });
    }
    const { userId, product, options } = payload;
    try {
      const user = await storage.getUser(userId);
      if (!user || (user as any).deletedAt) {
        return res.redirect(`${APP_BASE}/login?error=account_not_found`);
      }

      let sessionUrl: string | null = null;

      if (product === "studio_credits") {
        const packId = String(options.packId || "") as StudioPackId;
        const pack = STUDIO_CREDIT_PACKS[packId];
        if (!pack) return res.redirect(`${APP_BASE}/studio/credits?error=invalid_pack`);
        const stripeSession = await stripeMain.checkout.sessions.create({
          payment_method_types: ["card"],
          customer_email: user.email,
          line_items: [{
            price_data: {
              currency: "usd",
              product_data: { name: `GUBER Studio · ${pack.label}`, description: `${pack.credits} AI video credits for GUBER Studio.` },
              unit_amount: pack.priceCents,
            },
            quantity: 1,
          }],
          mode: "payment",
          success_url: resolveSuccessUrl(options.successUrl, `${APP_BASE}/studio/credits?purchased=1`),
          cancel_url: `${APP_BASE}/studio/credits`,
          metadata: { userId: String(user.id), userEmail: user.email, type: "studio_credits", packId, credits: String(pack.credits) },
        });
        sessionUrl = stripeSession.url;

      } else if (product === "studio_subscription") {
        const tierId = String(options.tier || "") as StudioTierPlanId;
        const plan = STUDIO_TIER_PLANS[tierId];
        if (!plan) return res.redirect(`${APP_BASE}/studio/credits?error=invalid_tier`);
        if (user.studioSubscriptionId) {
          return res.redirect(`${APP_BASE}/studio/credits?error=already_subscribed`);
        }
        const stripeSession = await stripeMain.checkout.sessions.create({
          payment_method_types: ["card"],
          customer_email: user.email,
          mode: "subscription",
          line_items: [{
            price_data: {
              currency: "usd",
              product_data: { name: plan.productName, description: plan.description },
              unit_amount: plan.priceCents,
              recurring: { interval: "month" },
            },
            quantity: 1,
          }],
          success_url: resolveSuccessUrl(options.successUrl, `${APP_BASE}/studio/credits?purchased=1`),
          cancel_url: `${APP_BASE}/studio/credits`,
          subscription_data: {
            metadata: { userId: String(user.id), userEmail: user.email, type: "studio_subscription", tier: tierId, monthlyCredits: String(plan.monthlyCredits) },
          },
          metadata: { userId: String(user.id), userEmail: user.email, type: "studio_subscription", tier: tierId, monthlyCredits: String(plan.monthlyCredits) },
        });
        sessionUrl = stripeSession.url;

      } else if (product === "day1og") {
        if (user.day1OG) return res.redirect(`${APP_BASE}/profile?error=already_og`);
        const stripeSession = await stripe.checkout.sessions.create({
          payment_method_types: ["card"],
          customer_email: user.email,
          line_items: [{
            price_data: {
              currency: "usd",
              product_data: { name: "GUBER Day-1 OG Lifetime Pass", description: "Permanent Day-1 OG status. Perk: free urgent toggle on all jobs." },
              unit_amount: 199,
            },
            quantity: 1,
          }],
          mode: "payment",
          success_url: resolveSuccessUrl(options.successUrl, `${APP_BASE}/profile?day1og=success`),
          cancel_url: `${APP_BASE}/profile`,
          metadata: { userId: String(user.id), userEmail: user.email, type: "day1og" },
        });
        sessionUrl = stripeSession.url;

      } else if (product === "trust_box") {
        if ((user as any).trustBoxPurchased && (user as any).trustBoxSubscriptionId) {
          return res.redirect(`${APP_BASE}/ai-or-not?error=already_subscribed`);
        }
        if (!TRUST_BOX_PAYROLL_PRICE_ID) {
          return res.redirect(`${APP_BASE}/ai-or-not?error=not_configured`);
        }
        const stripeSession = await stripe.checkout.sessions.create({
          payment_method_types: ["card"],
          customer_email: user.email,
          line_items: [{ price: TRUST_BOX_PAYROLL_PRICE_ID, quantity: 1 }],
          mode: "subscription",
          success_url: resolveSuccessUrl(options.successUrl, `${APP_BASE}/profile?trustbox=success`),
          cancel_url: `${APP_BASE}/ai-or-not`,
          subscription_data: {
            metadata: { userId: String(user.id), userEmail: user.email, type: "trust_box" },
          },
          metadata: { userId: String(user.id), userEmail: user.email, type: "trust_box" },
        });
        sessionUrl = stripeSession.url;

      } else if (product === "business_scout") {
        const acct = await storage.getBusinessAccount(userId);
        if (!acct) return res.redirect(`${APP_BASE}/biz/dashboard?error=no_account`);
        let customerId = acct.stripeCustomerId;
        if (!customerId) {
          const customer = await stripeMain.customers.create({
            email: acct.workEmail,
            name: acct.businessName,
            metadata: { businessAccountId: String(acct.id), userId: String(userId) },
          });
          customerId = customer.id;
          await storage.updateBusinessAccount(acct.id, { stripeCustomerId: customerId });
        }
        const stripeSession = await stripeMain.checkout.sessions.create({
          customer: customerId,
          mode: "subscription",
          line_items: [{
            price_data: {
              currency: "usd",
              product_data: { name: "GUBER Business Scout Plan", description: "Full Talent Explorer access, 20 profile unlocks/month, offer sending" },
              unit_amount: 9900,
              recurring: { interval: "month" },
            },
            quantity: 1,
          }],
          metadata: { type: "business_scout_plan", businessAccountId: String(acct.id) },
          success_url: resolveSuccessUrl(options.successUrl, `${APP_BASE}/biz/dashboard?subscribed=true&purchased=1`),
          cancel_url: `${APP_BASE}/biz/talent-explorer`,
        });
        sessionUrl = stripeSession.url;

      } else if (product === "business_unlock") {
        const acct = await storage.getBusinessAccount(userId);
        if (!acct) return res.redirect(`${APP_BASE}/biz/dashboard?error=no_account`);
        const qty = Math.max(1, Math.min(50, parseInt(String(options?.quantity || "5")) || 5));
        let customerId = acct.stripeCustomerId;
        if (!customerId) {
          const customer = await stripeMain.customers.create({
            email: acct.workEmail,
            name: acct.businessName,
            metadata: { businessAccountId: String(acct.id), userId: String(userId) },
          });
          customerId = customer.id;
          await storage.updateBusinessAccount(acct.id, { stripeCustomerId: customerId });
        }
        const stripeSession = await stripeMain.checkout.sessions.create({
          customer: customerId,
          mode: "payment",
          line_items: [{
            price_data: {
              currency: "usd",
              product_data: { name: "Additional Profile Unlocks", description: `${qty} additional profile unlock(s) for Talent Explorer` },
              unit_amount: 700,
            },
            quantity: qty,
          }],
          metadata: { type: "business_extra_unlocks", businessAccountId: String(acct.id), quantity: String(qty) },
          success_url: resolveSuccessUrl(options.successUrl, `${APP_BASE}/biz/dashboard?unlocks_purchased=true&purchased=1`),
          cancel_url: `${APP_BASE}/biz/dashboard`,
        });
        sessionUrl = stripeSession.url;

      } else if (product === "marketplace_buyer_order") {
        const itemId = parseInt(options.itemId || "0");
        const itemSlug = options.slug || "";
        if (!itemId) return res.redirect(`${APP_BASE}/marketplace?error=invalid_item`);
        const listingItem = await storage.getMarketplaceItem(itemId);
        if (!listingItem || !listingItem.vinNumber) return res.redirect(`${APP_BASE}/marketplace?error=no_vin`);
        const returnPath = itemSlug ? `/marketplace/p/${itemSlug}` : `/marketplace/${itemId}`;
        const stripeSession = await stripeMain.checkout.sessions.create({
          payment_method_types: ["card"],
          customer_email: user.email,
          line_items: [{
            price_data: {
              currency: "usd",
              product_data: { name: "GUBER Buyer's Order PDF", description: `Vehicle listing info sheet for: ${listingItem.title}` },
              unit_amount: 100,
            },
            quantity: 1,
          }],
          mode: "payment",
          success_url: `${APP_BASE}${returnPath}?buyer_order=paid&session_id={CHECKOUT_SESSION_ID}`,
          cancel_url: `${APP_BASE}${returnPath}`,
          metadata: { type: "marketplace_buyer_order", itemId: String(itemId), userId: String(user.id) },
        });
        sessionUrl = stripeSession.url;

      } else if (product === "asset_protection") {
        // Verified Release System package / witness add-on (iOS external purchase).
        const assetId = parseInt(String(options.assetId || "0"));
        const productType = String(options.productType || "");
        const key = String(options.key || "");
        if (!assetId || (productType !== "package" && productType !== "witness_addon") || !key) {
          return res.redirect(`${APP_BASE}/load-board?error=invalid_protection`);
        }
        const result = await buildAssetProtectionCheckout({
          userId: user.id,
          userEmail: user.email,
          productType: productType as "package" | "witness_addon",
          key,
          assetId,
          successUrl: resolveSuccessUrl(options.successUrl, `${APP_BASE}/load-board?protection=success`),
          cancelUrl: `${APP_BASE}/load-board`,
        });
        if ("error" in result) return res.redirect(`${APP_BASE}/load-board?error=protection_failed`);
        sessionUrl = result.url;

      } else if (product === "asset_protection_founders") {
        // Founders Club enrollment (iOS external purchase).
        const result = await buildFoundersCheckout({
          userId: user.id,
          userEmail: user.email,
          userRole: user.role,
          successUrl: resolveSuccessUrl(options.successUrl, `${APP_BASE}/load-board?founders=success`),
          cancelUrl: `${APP_BASE}/load-board`,
        });
        if ("error" in result) return res.redirect(`${APP_BASE}/load-board?error=founders_${result.code}`);
        sessionUrl = result.url;
      }

      if (!sessionUrl) return res.redirect(`${APP_BASE}/?error=unknown_product`);
      res.redirect(sessionUrl);
    } catch (err: any) {
      console.error("[GUBER][mobile-checkout-redirect] error:", err.message);
      res.redirect(`${APP_BASE}/?error=checkout_failed`);
    }
  });

  // ── GUBER Studio v2 — session-based generation ───────────────────────────
  // Every visit opens a session. Uploaded references and generated outputs
  // live for the lifetime of that session only — explicit exit, 30 min of
  // inactivity, or 1 hour of total age all purge the rows AND the
  // Cloudinary assets. Nothing pins to the user's profile.

  // Helper: purge a session's files from Cloudinary, then mark the session ended.
  async function purgeStudioSession(sessionId: number, reason: string) {
    const files = await storage.deleteStudioSessionFiles(sessionId);
    let cloudinary: any = null;
    try {
      if (process.env.CLOUDINARY_CLOUD_NAME) {
        cloudinary = (await import("./cloudinary.js")).default;
      }
    } catch {}
    if (cloudinary) {
      for (const f of files) {
        if (!f.cloudinaryPublicId) continue;
        try {
          await cloudinary.uploader.destroy(f.cloudinaryPublicId, { resource_type: f.resourceType || "image" });
        } catch (err: any) {
          console.warn(`[GUBER][studio] cloudinary destroy failed for ${f.cloudinaryPublicId}: ${err.message}`);
        }
      }
    }
    await storage.endStudioSession(sessionId, reason);
  }

