  // Resolve / open the user's active session, OR create a new one if missing.
  // Used by the generate endpoints below.
  async function ensureStudioSession(userId: number) {
    const existing = await storage.getActiveStudioSession(userId);
    if (existing) {
      await storage.touchStudioSession(existing.id);
      return existing;
    }
    return storage.createStudioSession(userId);
  }

  // Upload a reference media file into the current session. Returns the
  // public Cloudinary URL we'll feed into Fal calls.
  app.post("/api/studio/upload", requireAuth, async (req: Request, res: Response) => {
    try {
      const userId = req.session.userId!;
      const dataUrl = String(req.body?.dataUrl || "");
      const kind = String(req.body?.kind || "image"); // image | video | audio
      if (!dataUrl) return res.status(400).json({ message: "Missing file data" });
      if (!process.env.CLOUDINARY_CLOUD_NAME) {
        return res.status(503).json({ message: "Studio storage isn't configured yet." });
      }
      const cloudinary = (await import("./cloudinary.js")).default;
      const resourceType = kind === "image" ? "image" : "video";
      const up = await cloudinary.uploader.upload(dataUrl, {
        resource_type: resourceType,
        folder: "guber-studio-v2-uploads",
      });

      // Image-only moderation pre-check — fail-closed.
      if (kind === "image") {
        const { isModerationConfigured, moderateImage, ModerationUnavailableError } = await import("./fal");
        if (isModerationConfigured()) {
          try {
            const mod = await moderateImage(up.secure_url);
            if (mod.flagged) {
              try { await cloudinary.uploader.destroy(up.public_id, { resource_type: "image" }); } catch {}
              return res.status(400).json({ message: mod.reason || "Reference image blocked by content moderation." });
            }
          } catch (err: any) {
            if (err instanceof ModerationUnavailableError) {
              console.warn("[GUBER][studio] Image moderation unavailable — allowing upload through:", err.message);
              // fail-open: moderation blip should not block a legitimate upload
            } else {
              throw err;
            }
          }
        }
      }

      const session = await ensureStudioSession(userId);
      const file = await storage.addStudioSessionFile({
        sessionId: session.id,
        userId,
        fileType: kind === "image" ? "upload_image" : kind === "video" ? "upload_video" : "upload_audio",
        providerUrl: up.secure_url,
        cloudinaryPublicId: up.public_id,
        resourceType,
        meta: null,
      });
      res.json({ file });
    } catch (err: any) {
      res.status(500).json({ message: `Upload failed: ${err.message}` });
    }
  });

  // Shared lifecycle for every generate endpoint:
  //   1. Auth + session ensured.
  //   2. Validate input.
  //   3. Provider + moderation availability (503 if either is down).
  //   4. Lookup pricing row → creditsCost.
  //   5. Atomically deduct credits (402 if insufficient).
  //   6. Call provider. On failure → refund + 502.
  //   7. Re-host output on Cloudinary, attach to session, log success.
  async function runStudioGeneration(opts: {
    req: Request;
    res: Response;
    toolKey: string;
    prompt?: string | null;
    requireImage?: boolean;
    creditsCostOverride?: number;
    extraMeta?: Record<string, any>;
    runProvider: (input: { prompt: string; imageUrl?: string }) => Promise<{ url: string; jobId: string; resourceType: "video" | "image"; folder: string }>;
  }) {
    const { req, res, toolKey, runProvider, requireImage } = opts;
    const userId = req.session.userId!;

    const promptRaw = (opts.prompt ?? "").toString().trim();
    if (promptRaw.length > 500) {
      return res.status(400).json({ message: "Prompt is too long (max 500 characters)." });
    }

    const sourceFileId = req.body?.sourceFileId ? parseInt(String(req.body.sourceFileId), 10) : null;
    const session = await ensureStudioSession(userId);

    let imageUrl: string | undefined;
    if (sourceFileId) {
      const files = await storage.listStudioSessionFiles(session.id);
      const f = files.find((x) => x.id === sourceFileId && x.userId === userId);
      if (!f) return res.status(404).json({ message: "Reference file not found in your current session." });
      imageUrl = f.providerUrl;
    }
    if (requireImage && !imageUrl) {
      return res.status(400).json({ message: "This tool needs a reference image. Upload one and try again." });
    }
    if (!promptRaw && !imageUrl) {
      return res.status(400).json({ message: "Add a prompt or upload a reference to start." });
    }

    const { isFalConfigured, isModerationConfigured, moderatePrompt, ModerationUnavailableError, FalNotConfiguredError } = await import("./fal");
    if (!isFalConfigured()) {
      return res.status(503).json({ message: "GUBER Studio is temporarily unavailable: AI provider not connected. Your credits are safe." });
    }
    if (promptRaw) {
      if (isModerationConfigured()) {
        try {
          const mod = await moderatePrompt(promptRaw);
          if (mod.flagged) {
            return res.status(400).json({ message: mod.reason || "Prompt blocked by content moderation." });
          }
        } catch (err: any) {
          if (err instanceof ModerationUnavailableError) {
            console.warn("[GUBER][studio] Prompt moderation unavailable — allowing generation through:", err.message);
            // fail-open: transient OpenAI outage should not block generation
          } else {
            throw err;
          }
        }
      }
    }

    const pricing = await storage.getStudioModelPricing(toolKey);
    if (!pricing) return res.status(400).json({ message: "Unknown tool." });
    const creditsCost = opts.creditsCostOverride ?? pricing.creditsCost;

    // Admins have unlimited generation access — credits are still deducted
    // for cost tracking, but the balance gate is skipped entirely.
    const actingUser = await storage.getUser(userId);
    const isAdminUser = actingUser?.role === "admin";

    let newBalance: number;
    if (isAdminUser) {
      // Unconditional deduction — can go negative, no 402 gate.
      newBalance = await storage.incrementStudioCredits(userId, -creditsCost);
    } else {
      const result = await storage.decrementStudioCredits(userId, creditsCost);
      if (result === null) {
        return res.status(402).json({ message: "Not enough Studio credits. Buy a credit pack to keep creating." });
      }
      newBalance = result;
    }

    // task-541: track Cloudinary assets we re-host so any failure between
    // upload and the studio_session_files row write destroys them — no
    // orphans in paid storage.
    const { createCloudinaryCleanup } = await import("./studio/cloudinary-cleanup");
    let cloudinary: any = null;
    try {
      if (process.env.CLOUDINARY_CLOUD_NAME) {
        cloudinary = (await import("./cloudinary.js")).default;
      }
    } catch {}
    const cleanup = createCloudinaryCleanup(cloudinary);

    try {
      const provider = await runProvider({ prompt: promptRaw, imageUrl });

      // Re-host on Cloudinary so we control the URL + can purge it on session end.
      let finalUrl = provider.url;
      let cloudinaryPublicId: string | null = null;
      const effectiveResourceType: "video" | "image" =
        provider.resourceType === "image" ? "image" : "video";
      try {
        if (cloudinary) {
          const uploaded = await cloudinary.uploader.upload(provider.url, {
            resource_type: provider.resourceType,
            folder: provider.folder,
          });
          finalUrl = uploaded.secure_url;
          cloudinaryPublicId = uploaded.public_id;
          cleanup.track(cloudinaryPublicId, effectiveResourceType);
        }
      } catch (err: any) {
        console.warn(`[GUBER][studio v2] cloudinary re-host failed for ${toolKey}: ${err.message}`);
      }

      const file = await storage.addStudioSessionFile({
        sessionId: session.id,
        userId,
        fileType: provider.resourceType === "video" ? "output_video" : "output_audio",
        providerUrl: finalUrl,
        cloudinaryPublicId,
        resourceType: provider.resourceType,
        meta: { toolKey, prompt: promptRaw, providerJobId: provider.jobId, creditsCost, ...(opts.extraMeta || {}) },
      });

      // The asset is now persisted to studio_session_files and owned by the
      // user — drop it from the cleanup list IMMEDIATELY so any late failure
      // in touchStudioSession / logStudioGeneration doesn't destroy a file
      // we just handed over.
      cleanup.clear();

      await storage.touchStudioSession(session.id);
      await storage.logStudioGeneration({
        userId,
        sessionId: session.id,
        toolKey,
        prompt: promptRaw || null,
        creditsCost,
        durationSeconds: pricing.durationSeconds ?? null,
        providerJobId: provider.jobId,
        status: "succeeded",
        errorReason: null,
      });

      res.json({ file, balance: newBalance });
    } catch (err: any) {
      await cleanup.cleanup(toolKey);
      const refunded = await storage.incrementStudioCredits(userId, creditsCost);
      await storage.logStudioGeneration({
        userId,
        sessionId: session.id,
        toolKey,
        prompt: promptRaw || null,
        creditsCost,
        durationSeconds: pricing.durationSeconds ?? null,
        providerJobId: null,
        status: "refunded",
        errorReason: err?.message?.slice(0, 500) || "Unknown generation error",
      });
      const isConfigErr = err?.name === "FalNotConfiguredError";
      res.status(isConfigErr ? 503 : 502).json({
        message: isConfigErr
          ? "AI provider not connected — your credit was returned."
          : `Generation failed and your credit was returned: ${err.message}`,
        balance: refunded,
      });
    }
  }

  app.post("/api/studio/generate/motion-control", requireAuth, async (req: Request, res: Response) => {
    const { generateKlingMotionControl } = await import("./fal");
    return runStudioGeneration({
      req, res, toolKey: "kling_motion_control",
      prompt: req.body?.prompt,
      requireImage: true,
      runProvider: async ({ prompt, imageUrl }) => {
        const r = await generateKlingMotionControl({ prompt, imageUrl: imageUrl!, durationSeconds: 5 });
        return { url: r.videoUrl, jobId: r.jobId, resourceType: "video", folder: "guber-studio-v2-motion" };
      },
    });
  });

  app.post("/api/studio/generate/wan-motion", requireAuth, async (req: Request, res: Response) => {
    const { generateWanMotion } = await import("./fal");
    const requestedDur = parseInt(String(req.body?.durationSeconds || "5"), 10);
    const dur = (requestedDur === 10 ? 10 : 5) as 5 | 10;
    const toolKey = dur === 10 ? "wan_motion_10s" : "wan_motion_5s";
    return runStudioGeneration({
      req, res, toolKey,
      prompt: req.body?.prompt,
      runProvider: async ({ prompt, imageUrl }) => {
        const r = await generateWanMotion({ prompt, imageUrl, durationSeconds: dur });
        return { url: r.videoUrl, jobId: r.jobId, resourceType: "video", folder: "guber-studio-v2-wan" };
      },
    });
  });

  // Free Quick Pic — 3 per UTC day per logged-in user. No credits deducted on
  // free path. Returns 429 when daily quota exhausted. Provider failure
  // refunds the quota (decrement used_count).
  const FREE_QUICKPIC_DAILY_LIMIT = 3;
  function utcDayString(d = new Date()): string {
    return d.toISOString().slice(0, 10);
  }

  app.get("/api/studio/free-quota", requireAuth, async (req: Request, res: Response) => {
    const userId = req.session.userId!;
    const day = utcDayString();
    const { isFeatureEnabledFor } = await import("./feature-flags.js");
    const user = await storage.getUser(userId);
    const enabled = await isFeatureEnabledFor("free_quickpic_enabled", user ? { id: user.id, role: user.role } : null);
    const used = await storage.getStudioFreeQuotaUsed(userId, day);
    const remaining = Math.max(FREE_QUICKPIC_DAILY_LIMIT - used, 0);
    res.json({
      enabled,
      day,
      dailyLimit: FREE_QUICKPIC_DAILY_LIMIT,
      used,
      remaining,
    });
  });

  app.post("/api/studio/generate/quick-pic", requireAuth, async (req: Request, res: Response) => {
    const userId = req.session.userId!;
    const promptRaw = String(req.body?.prompt ?? "").trim();
    if (!promptRaw) return res.status(400).json({ message: "Add a prompt to generate a Quick Pic." });
    if (promptRaw.length > 500) return res.status(400).json({ message: "Prompt is too long (max 500 characters)." });

    const { isFeatureEnabledFor } = await import("./feature-flags.js");
    const user = await storage.getUser(userId);
    const enabled = await isFeatureEnabledFor("free_quickpic_enabled", user ? { id: user.id, role: user.role } : null);
    if (!enabled) {
      return res.status(403).json({ message: "Free Quick Pic is currently disabled." });
    }

    const {
      isFalConfigured, isModerationConfigured, moderatePrompt,
      ModerationUnavailableError, generateFluxQuickPic,
    } = await import("./fal");
    if (!isFalConfigured()) {
      return res.status(503).json({ message: "GUBER Studio is temporarily unavailable: AI provider not connected. Your free quota is safe." });
    }
    if (isModerationConfigured()) {
      try {
        const mod = await moderatePrompt(promptRaw);
        if (mod.flagged) {
          return res.status(400).json({ message: mod.reason || "Prompt blocked by content moderation." });
        }
      } catch (err: any) {
        if (err instanceof ModerationUnavailableError) {
          console.warn("[GUBER][studio] Prompt moderation unavailable — allowing Quick Pic through:", err.message);
        } else {
          throw err;
        }
      }
    }

    const day = utcDayString();
    const newUsed = await storage.consumeStudioFreeQuota(userId, day, FREE_QUICKPIC_DAILY_LIMIT);
    if (newUsed === null) {
      return res.status(429).json({
        message: `You've used your ${FREE_QUICKPIC_DAILY_LIMIT} free Quick Pics for today. Come back tomorrow (UTC) for more.`,
        dailyLimit: FREE_QUICKPIC_DAILY_LIMIT,
        used: FREE_QUICKPIC_DAILY_LIMIT,
        remaining: 0,
      });
    }
    const remaining = Math.max(FREE_QUICKPIC_DAILY_LIMIT - newUsed, 0);

    const session = await ensureStudioSession(userId);
    const pricing = await storage.getStudioModelPricing("flux_quick_pic");

    try {
      const provider = await generateFluxQuickPic({ prompt: promptRaw });

      let finalUrl = provider.imageUrl;
      let cloudinaryPublicId: string | null = null;
      try {
        if (process.env.CLOUDINARY_CLOUD_NAME) {
          const cloudinary = (await import("./cloudinary.js")).default;
          const uploaded = await cloudinary.uploader.upload(provider.imageUrl, {
            resource_type: "image",
            folder: "guber-studio-v2-quickpic",
          });
          finalUrl = uploaded.secure_url;
          cloudinaryPublicId = uploaded.public_id;
        }
      } catch (err: any) {
        console.warn(`[GUBER][studio v2] cloudinary re-host failed for flux_quick_pic: ${err.message}`);
      }

      const file = await storage.addStudioSessionFile({
        sessionId: session.id,
        userId,
        fileType: "output_image",
        providerUrl: finalUrl,
        cloudinaryPublicId,
        resourceType: "image",
        meta: { toolKey: "flux_quick_pic", prompt: promptRaw, providerJobId: provider.jobId, billing: "free", freeUsed: newUsed },
      });

      await storage.touchStudioSession(session.id);
      await storage.logStudioGeneration({
        userId,
        sessionId: session.id,
        toolKey: "flux_quick_pic",
        prompt: promptRaw,
        creditsCost: 0,
        durationSeconds: pricing?.durationSeconds ?? null,
        providerJobId: provider.jobId,
        status: "succeeded",
        errorReason: null,
      });

      res.json({
        file,
        billing: "free",
        dailyLimit: FREE_QUICKPIC_DAILY_LIMIT,
        used: newUsed,
        remaining,
      });
    } catch (err: any) {
      // Refund the free-quota slot exactly the way credits are refunded.
      await storage.refundStudioFreeQuota(userId, day);
      await storage.logStudioGeneration({
        userId,
        sessionId: session.id,
        toolKey: "flux_quick_pic",
        prompt: promptRaw,
        creditsCost: 0,
        durationSeconds: pricing?.durationSeconds ?? null,
        providerJobId: null,
        status: "refunded",
        errorReason: err?.message?.slice(0, 500) || "Unknown generation error",
      });
      const isConfigErr = err?.name === "FalNotConfiguredError";
      const refundedUsed = Math.max(newUsed - 1, 0);
      res.status(isConfigErr ? 503 : 502).json({
        message: isConfigErr
          ? "AI provider not connected — your free Quick Pic was returned."
          : `Quick Pic failed and your free generation was returned: ${err.message}`,
        dailyLimit: FREE_QUICKPIC_DAILY_LIMIT,
        used: refundedUsed,
        remaining: Math.max(FREE_QUICKPIC_DAILY_LIMIT - refundedUsed, 0),
      });
    }
  });

  app.post("/api/studio/generate/music", requireAuth, async (req: Request, res: Response) => {
    const { generateMiniMaxMusic } = await import("./fal");
    return runStudioGeneration({
      req, res, toolKey: "minimax_music",
      prompt: req.body?.prompt,
      runProvider: async ({ prompt }) => {
        const r = await generateMiniMaxMusic({ prompt });
        return { url: r.audioUrl, jobId: r.jobId, resourceType: "video", folder: "guber-studio-v2-music" };
      },
    });
  });

  // ── Mirror Motion (task-521) ─────────────────────────────────────────────
  // Photo + reference-clip motion-clone via Kling motion-control. Server-priced
  // at 16 cr × seconds (5 or 10 only). Reference clip MUST be a direct media
  // URL (no yt-dlp dep yet — UI flags this explicitly).
  app.post("/api/studio/generate/mirror-motion", requireAuth, async (req: Request, res: Response) => {
    const motionVideoUrl = String(req.body?.motionVideoUrl || "").trim();
    const requestedDur = parseInt(String(req.body?.durationSeconds || "5"), 10);
    const dur = (requestedDur === 10 ? 10 : 5) as 5 | 10;
    const audioRightsConfirmed = req.body?.audioRightsConfirmed === true;

    if (!/^https:\/\//i.test(motionVideoUrl)) {
      return res.status(400).json({ message: "Provide a direct https:// URL to the reference clip (.mp4 / .mov)." });
    }
    if (!/\.(mp4|mov|webm|m4v)(\?|$)/i.test(motionVideoUrl)) {
      return res.status(400).json({ message: "Reference clip must be a direct video file (.mp4, .mov, .webm). YouTube / TikTok links aren't supported yet." });
    }
    if (!audioRightsConfirmed) {
      return res.status(400).json({ message: "You must confirm you have the rights to clone the reference clip's audio/motion before continuing." });
    }

    // Audit the rights confirmation immediately (option-C posture).
    try {
      await storage.createAuditLog({
        userId: req.session.userId!,
        action: "studio.mirror_motion.rights_confirmed",
        details: `Mirror Motion run authorized for ${motionVideoUrl} (${dur}s)`,
      });
    } catch {}

    const { generateMirrorMotion } = await import("./fal");
    return runStudioGeneration({
      req, res,
      toolKey: "mirror_motion",
      prompt: req.body?.prompt,
      requireImage: true,
      creditsCostOverride: 16 * dur,
      extraMeta: { motionVideoUrl, durationSeconds: dur, audioRightsConfirmed: true },
      runProvider: async ({ prompt, imageUrl }) => {
        const r = await generateMirrorMotion({
          prompt: prompt || "Mirror the motion of the reference clip onto the supplied photo with cinematic fidelity.",
          imageUrl: imageUrl!,
          motionVideoUrl,
          durationSeconds: dur,
        });
        return { url: r.videoUrl, jobId: r.jobId, resourceType: "video", folder: "guber-studio-v2-mirror" };
      },
    });
  });

  // ── Commercial Builder (task-521) ────────────────────────────────────────
  // Composite ad pipeline: motion-control video → music (with one retry) →
  // optional OpenAI TTS voiceover. Atomic credit spend up front; ANY hard
  // failure refunds and aborts. Each artifact is attached to the session as
  // its own studio_session_files row so the user can download them separately.
  app.post("/api/studio/generate/commercial", requireAuth, async (req: Request, res: Response) => {
    const userId = req.session.userId!;
    let creditsDebited = 0;  // tracked so the outer catch can refund post-debit
    let postDebitSessionId: number | null = null;
    let postDebitMotionPrompt = "";
    let postDebitCloudinary: any = null;
    let postDebitDurationSeconds: number | null = null;
    // Track every Cloudinary asset re-hosted during this run so any
    // refund/abort path can best-effort destroy ALL of them and never
    // leave orphans in paid storage (task-538). Lifted into a shared
    // helper in task-541 so wan_motion / kling / mirror_motion / music
    // get the same guarantee via runStudioGeneration().
    const { createCloudinaryCleanup } = await import("./studio/cloudinary-cleanup");
    let commercialCleanup = createCloudinaryCleanup(null);
    const cleanupCloudinaryAssets = async () => {
      await commercialCleanup.cleanup("commercial");
    };
    try {
      const verticalSlug = String(req.body?.vertical || "").trim();
      const customVertical = String(req.body?.customVertical || "").trim();
      const businessName = String(req.body?.businessName || "").trim();
      const businessDescription = String(req.body?.businessDescription || "").trim();
      const ctaText = String(req.body?.ctaText || "").trim();
      const sourceFileId = req.body?.productPhotoFileId
        ? parseInt(String(req.body.productPhotoFileId), 10)
        : null;
      const voiceId = req.body?.voiceId ? String(req.body.voiceId) : null;

      if (!businessName || businessName.length > 80) return res.status(400).json({ message: "Business name is required (≤80 chars)." });
      if (!businessDescription || businessDescription.length > 400) return res.status(400).json({ message: "Business description is required (≤400 chars)." });
      if (!ctaText || ctaText.length > 80) return res.status(400).json({ message: "CTA text is required (≤80 chars)." });
      if (!sourceFileId) return res.status(400).json({ message: "Upload a product photo first." });

      const verticalsMod = await import("../shared/commercial-verticals");
      const vertical = verticalsMod.getVertical(verticalSlug);
      if (!vertical) return res.status(400).json({ message: "Unknown vertical." });
      if (vertical.slug === "custom" && !customVertical) {
        return res.status(400).json({ message: "Describe your business vertical in 1–3 words." });
      }
      const customVerticalLabel = vertical.slug === "custom" ? customVertical : vertical.label;

      if (voiceId) {
        const ok = verticalsMod.OPENAI_TTS_VOICES.some((v) => v.id === voiceId);
        if (!ok) return res.status(400).json({ message: "Unknown voice id." });
      }

      const session = await ensureStudioSession(userId);
      const files = await storage.listStudioSessionFiles(session.id);
      const photo = files.find((f) => f.id === sourceFileId && f.userId === userId && f.fileType === "upload_image");
      if (!photo) return res.status(404).json({ message: "Product photo not found in your current session." });

      const { isFalConfigured, isModerationConfigured, moderatePrompt, ModerationUnavailableError, isOpenAITtsConfigured } = await import("./fal");
      if (!isFalConfigured()) {
        return res.status(503).json({ message: "GUBER Studio is temporarily unavailable: AI provider not connected. Your credits are safe." });
      }
      const motionPrompt = verticalsMod.renderTemplate(vertical.motionPromptTemplate, {
        businessName, businessDescription, ctaText, customVertical: customVerticalLabel,
      });
      const musicPrompt = verticalsMod.renderTemplate(vertical.musicPromptTemplate, {
        businessName, businessDescription, ctaText, customVertical: customVerticalLabel,
      });
      const voicePrompt = verticalsMod.renderTemplate(vertical.voicePromptTemplate, {
        businessName, businessDescription, ctaText, customVertical: customVerticalLabel,
      });
      if (isModerationConfigured()) {
        try {
          const mod = await moderatePrompt(`${businessName}\n${businessDescription}\n${ctaText}\n${customVerticalLabel}`);
          if (mod.flagged) return res.status(400).json({ message: mod.reason || "Commercial copy blocked by moderation." });
        } catch (err: any) {
          if (err instanceof ModerationUnavailableError) {
            console.warn("[GUBER][studio] Commercial moderation unavailable — allowing through:", err.message);
          } else {
            throw err;
          }
        }
      }

      const pricing = await storage.getStudioModelPricing("commercial_builder");
      if (!pricing) return res.status(400).json({ message: "Commercial Builder pricing missing — contact support." });
      const creditsCost = pricing.creditsCost;

      const newBalance = await storage.decrementStudioCredits(userId, creditsCost);
      if (newBalance === null) {
        return res.status(402).json({ message: "Not enough Studio credits. Buy a credit pack to keep creating." });
      }
      creditsDebited = creditsCost;
      postDebitSessionId = session.id;
      postDebitMotionPrompt = motionPrompt;
      postDebitDurationSeconds = pricing.durationSeconds ?? null;

      let cloudinary: any = null;
      try {
        if (process.env.CLOUDINARY_CLOUD_NAME) {
          cloudinary = (await import("./cloudinary.js")).default;
        }
      } catch {}
      postDebitCloudinary = cloudinary;
      commercialCleanup = createCloudinaryCleanup(cloudinary);

      const reHost = async (sourceUrlOrDataUrl: string, resourceType: "video" | "image" | "raw", folder: string): Promise<{ url: string; publicId: string | null }> => {
        if (!cloudinary) return { url: sourceUrlOrDataUrl, publicId: null };
        try {
          const effectiveResourceType = resourceType === "image" ? "image" : "video";
          const up = await cloudinary.uploader.upload(sourceUrlOrDataUrl, {
            resource_type: effectiveResourceType,
            folder,
          });
          commercialCleanup.track(up.public_id, effectiveResourceType);
          return { url: up.secure_url, publicId: up.public_id };
        } catch (err: any) {
          console.warn(`[GUBER][studio][commercial] cloudinary re-host failed: ${err.message}`);
          return { url: sourceUrlOrDataUrl, publicId: null };
        }
      };

      const refundAndAbort = async (httpStatus: number, message: string, providerJobId: string | null = null) => {
        await cleanupCloudinaryAssets();
        const refunded = await storage.incrementStudioCredits(userId, creditsCost);
        await storage.logStudioGeneration({
          userId, sessionId: session.id, toolKey: "commercial_builder",
          prompt: motionPrompt.slice(0, 500), creditsCost,
          durationSeconds: pricing.durationSeconds ?? null,
          providerJobId, status: "refunded",
          errorReason: message.slice(0, 500),
        });
        return res.status(httpStatus).json({ message: `Generation failed and your credits were returned: ${message}`, balance: refunded });
      };

      // Step 1: motion-control video (Kling) — REQUIRED.
      const { generateKlingMotionControl, generateMiniMaxMusic, generateOpenAITts, OpenAITtsUnavailableError } = await import("./fal");
      let motionUrl = "", motionJobId = "", motionPublicId: string | null = null;
      try {
        const r = await generateKlingMotionControl({
          prompt: motionPrompt, imageUrl: photo.providerUrl, durationSeconds: 10,
        });
        motionJobId = r.jobId;
        const reh = await reHost(r.videoUrl, "video", "guber-studio-v2-commercial");
        motionUrl = reh.url; motionPublicId = reh.publicId;
      } catch (err: any) {
        return refundAndAbort(502, `Motion render failed: ${err.message}`, null);
      }

      // Step 2: music (MiniMax) — one retry on failure, refund if both fail.
      let musicUrl: string | null = null, musicJobId: string | null = null, musicPublicId: string | null = null;
      let musicError: string | null = null;
      for (let attempt = 1; attempt <= 2; attempt++) {
        try {
          const r = await generateMiniMaxMusic({ prompt: musicPrompt });
          musicJobId = r.jobId;
          const reh = await reHost(r.audioUrl, "video", "guber-studio-v2-commercial-music");
          musicUrl = reh.url; musicPublicId = reh.publicId;
          break;
        } catch (err: any) {
          musicError = err.message;
          console.warn(`[GUBER][studio][commercial] music attempt ${attempt} failed: ${err.message}`);
        }
      }
      if (!musicUrl) {
        return refundAndAbort(502, `Music render failed twice: ${musicError || "unknown"}`, motionJobId);
      }

      // Step 3 (optional): voiceover via OpenAI TTS. If the user requested a
      // voice and the provider hard-fails, refund the full bundle (task-537)
      // — the user paid for a 3-piece deliverable. If TTS is simply not
      // configured we still skip with a note (no provider call attempted).
      let voiceUrl: string | null = null, voicePublicId: string | null = null;
      let voiceSkippedReason: string | null = null;
      if (voiceId) {
        if (!isOpenAITtsConfigured()) {
          voiceSkippedReason = "TTS provider not configured";
        } else {
          try {
            const tts = await generateOpenAITts({ text: voicePrompt, voice: voiceId });
            const reh = await reHost(tts.dataUrl, "video", "guber-studio-v2-commercial-voice");
            voiceUrl = reh.url; voicePublicId = reh.publicId;
          } catch (err: any) {
            console.warn(`[GUBER][studio][commercial] voiceover failed: ${err.message}`);
            const reason = err instanceof OpenAITtsUnavailableError
              ? "TTS provider offline"
              : (err.message?.slice(0, 200) || "voiceover failed");
            return refundAndAbort(502, `Voiceover failed: ${reason}`, motionJobId);
          }
        }
      }

      const baseMeta = {
        toolKey: "commercial_builder",
        creditsCost,
        vertical: vertical.slug,
        verticalLabel: customVerticalLabel,
        businessName,
        ctaText,
      };

      const motionFile = await storage.addStudioSessionFile({
        sessionId: session.id, userId,
        fileType: "output_video",
        providerUrl: motionUrl,
        cloudinaryPublicId: motionPublicId,
        resourceType: "video",
        meta: { ...baseMeta, kind: "commercial_motion", prompt: motionPrompt, providerJobId: motionJobId },
      });
      const musicFile = await storage.addStudioSessionFile({
        sessionId: session.id, userId,
        fileType: "output_audio",
        providerUrl: musicUrl,
        cloudinaryPublicId: musicPublicId,
        resourceType: "video",
        meta: { ...baseMeta, kind: "commercial_music", prompt: musicPrompt, providerJobId: musicJobId },
      });
      const voiceFile = voiceUrl ? await storage.addStudioSessionFile({
        sessionId: session.id, userId,
        fileType: "output_audio",
        providerUrl: voiceUrl,
        cloudinaryPublicId: voicePublicId,
        resourceType: "video",
        meta: { ...baseMeta, kind: "commercial_voice", prompt: voicePrompt },
      }) : null;

      // Assets are now persisted to studio_session_files and belong to the
      // user — drop them from the cleanup list so any late failure on the
      // bookkeeping below doesn't destroy files we just handed over.
      commercialCleanup.clear();

      await storage.touchStudioSession(session.id);
      await storage.logStudioGeneration({
        userId, sessionId: session.id, toolKey: "commercial_builder",
        prompt: motionPrompt.slice(0, 500), creditsCost,
        durationSeconds: pricing.durationSeconds ?? null,
        providerJobId: motionJobId, status: "succeeded",
        errorReason: voiceSkippedReason ? `voiceover_skipped: ${voiceSkippedReason}` : null,
      });

      res.json({
        files: [motionFile, musicFile, ...(voiceFile ? [voiceFile] : [])],
        balance: newBalance,
        voiceSkippedReason,
      });
    } catch (err: any) {
      console.error("[GUBER][studio][commercial] unexpected:", err);
      // Defensive refund: if we already debited credits before the unexpected
      // error, return them and best-effort destroy every Cloudinary asset
      // we re-hosted during this run (motion + music + voice) so we never
      // leave orphans in paid storage (task-538).
      let refundedBalance: number | null = null;
      if (creditsDebited > 0) {
        try {
          refundedBalance = await storage.incrementStudioCredits(userId, creditsDebited);
        } catch (refundErr) {
          console.error("[GUBER][studio][commercial] refund failed:", refundErr);
        }
        await cleanupCloudinaryAssets();
        try {
          await storage.logStudioGeneration({
            userId,
            sessionId: postDebitSessionId ?? 0,
            toolKey: "commercial_builder",
            prompt: postDebitMotionPrompt.slice(0, 500),
            creditsCost: creditsDebited,
            durationSeconds: postDebitDurationSeconds,
            providerJobId: null,
            status: "refunded",
            errorReason: `unexpected: ${(err.message || "unknown").slice(0, 480)}`,
          });
        } catch {}
      }
      const note = creditsDebited > 0
        ? "Generation failed and your credits were returned."
        : "Unexpected error";
      res.status(500).json({ message: `${note} ${err.message || ""}`.trim(), balance: refundedBalance });
    }
  });

  // ── Listing Video: slideshow + narration + music + fantasy ending ────────
  // POST /api/studio/generate/listing-video
  // Body: { listingId, selectedPhotoUrls[], narrationText, voiceId?, musicGenre, fantasyPrompt }
  // Cost: photoCount×30 + 30 (fantasy) + 5 (music) + 5 (narration if voiceId set).
  // All fal.ai calls run in parallel — total wall time ~60–90s regardless of count.
  app.post("/api/studio/generate/listing-video", requireAuth, async (req: Request, res: Response) => {
    const userId = req.session.userId!;
    let creditsDebited = 0;
    let postDebitSessionId: number | null = null;
    let postDebitPrompt = "";
    const TOOL_KEY = "listing_video";

    const MUSIC_GENRE_PROMPTS: Record<string, string> = {
      luxury:   "Cinematic luxury orchestral background music, smooth and elegant, premium product advertisement",
      upbeat:   "Upbeat energetic background music, modern retail vibe, positive energy, commercial",
      chill:    "Chill lofi background music, warm relaxing vibes, mellow and comfortable",
      dramatic: "Epic dramatic cinematic background music, powerful and inspiring, adventure",
      romantic: "Romantic warm background music, emotional and heartfelt, soft piano and strings",
      hype:     "Urban hype background music, modern trap beats, street energy, bold and confident",
    };

    const { createCloudinaryCleanup } = await import("./studio/cloudinary-cleanup");
    let listingCleanup = createCloudinaryCleanup(null);
    const cleanupCloudinaryAssets = async () => { await listingCleanup.cleanup("listing-video"); };

    try {
      // ── Parse inputs ─────────────────────────────────────────────────────
      const listingId = req.body?.listingId ? parseInt(String(req.body.listingId), 10) : null;
      const rawPhotos: unknown = req.body?.selectedPhotoUrls;
      const selectedPhotoUrls: string[] = Array.isArray(rawPhotos)
        ? (rawPhotos as unknown[]).filter((u) => typeof u === "string").slice(0, 3) as string[]
        : [];
      const narrationText = typeof req.body?.narrationText === "string" ? req.body.narrationText.trim().slice(0, 500) : "";
      const voiceId = typeof req.body?.voiceId === "string" ? req.body.voiceId : null;
      const musicGenre = typeof req.body?.musicGenre === "string" ? req.body.musicGenre : "luxury";
      const fantasyPrompt = typeof req.body?.fantasyPrompt === "string" ? req.body.fantasyPrompt.trim().slice(0, 300) : "";

      if (!listingId || isNaN(listingId)) return res.status(400).json({ message: "listingId is required." });
      if (selectedPhotoUrls.length === 0) return res.status(400).json({ message: "At least one photo URL is required." });
      if (!fantasyPrompt) return res.status(400).json({ message: "fantasyPrompt is required." });

      // ── Validate listing ownership ────────────────────────────────────────
      const listing = await storage.getMarketplaceItem(listingId);
      if (!listing) return res.status(404).json({ message: "Listing not found." });
      if ((listing as any).sellerId !== userId && (listing as any).userId !== userId) {
        return res.status(403).json({ message: "You can only create videos for your own listings." });
      }

      // ── Validate voice ───────────────────────────────────────────────────
      const VALID_VOICES = ["alloy", "echo", "fable", "onyx", "nova", "shimmer"];
      if (voiceId && !VALID_VOICES.includes(voiceId)) return res.status(400).json({ message: "Invalid voice id." });

      const session = await ensureStudioSession(userId);

      // ── Dynamic credit cost ───────────────────────────────────────────────
      // Each slideshow photo = 30cr, fantasy clip = 30cr, music = 5cr, narration = 5cr
      const creditsCost = selectedPhotoUrls.length * 30 + 30 + 5 + (voiceId ? 5 : 0);

      // Auto-seed listing_video pricing metadata row on first use.
      const { studioModelPricing: studioModelPricingTable } = await import("../shared/schema");
      await db.insert(studioModelPricingTable).values({
        toolKey: TOOL_KEY,
        label: "Listing Video",
        description: "Animated slideshow + narration + music + fantasy ending for marketplace listings.",
        providerEndpoint: "fal-ai/wan-motion",
        creditsCost: 65,
        durationSeconds: 5,
        active: true,
      }).onConflictDoNothing();

      const newBalance = await storage.decrementStudioCredits(userId, creditsCost);
      if (newBalance === null) {
        return res.status(402).json({ message: "Not enough Studio credits. Buy a credit pack to keep creating." });
      }
      creditsDebited = creditsCost;
      postDebitSessionId = session.id;

      // ── Cloudinary helper ─────────────────────────────────────────────────
      let cloudinary: any = null;
      try {
        if (process.env.CLOUDINARY_CLOUD_NAME) cloudinary = (await import("./cloudinary.js")).default;
      } catch {}
      listingCleanup = createCloudinaryCleanup(cloudinary);

      const reHost = async (url: string, resourceType: "video" | "image", folder: string): Promise<{ url: string; publicId: string | null }> => {
        if (!cloudinary) return { url, publicId: null };
        try {
          const up = await cloudinary.uploader.upload(url, { resource_type: resourceType === "image" ? "image" : "video", folder });
          listingCleanup.track(up.public_id, resourceType === "image" ? "image" : "video");
          return { url: up.secure_url, publicId: up.public_id };
        } catch (err: any) {
          console.warn(`[GUBER][studio][listing-video] cloudinary re-host failed: ${err.message}`);
          return { url, publicId: null };
        }
      };

      const title = (listing as any).title ?? "Item for sale";
      const category = (listing as any).category ?? "";
      const slidePrompt = `Smooth cinematic product showcase of ${title}. ${category ? `${category} item. ` : ""}High-end retail aesthetic, elegant motion, warm studio lighting, social media ad.`;
      const musicPrompt = MUSIC_GENRE_PROMPTS[musicGenre] ?? MUSIC_GENRE_PROMPTS["luxury"];

      postDebitPrompt = slidePrompt;

      const refundAndAbort = async (httpStatus: number, message: string) => {
        await cleanupCloudinaryAssets();
        const refunded = await storage.incrementStudioCredits(userId, creditsCost);
        await storage.logStudioGeneration({
          userId, sessionId: session.id, toolKey: TOOL_KEY,
          prompt: slidePrompt.slice(0, 500), creditsCost,
          durationSeconds: 5, providerJobId: null, status: "refunded",
          errorReason: message.slice(0, 500),
        });
        return res.status(httpStatus).json({ message: `Generation failed and your credits were returned: ${message}`, balance: refunded });
      };

      const { generateWanMotion, generateMiniMaxMusic, generateOpenAITts, isOpenAITtsConfigured, OpenAITtsUnavailableError } = await import("./fal");

      // ── Parallel generation ───────────────────────────────────────────────
      // All fal.ai calls fire simultaneously. Wall time ≈ max(individual_times) ≈ 60–90s.
      const [slideResults, fantasyResult, musicResult, ttsResult] = await Promise.allSettled([
        Promise.all(selectedPhotoUrls.map((imgUrl) =>
          generateWanMotion({ prompt: slidePrompt, imageUrl: imgUrl, durationSeconds: 5 })
        )),
        generateWanMotion({ prompt: fantasyPrompt, durationSeconds: 5 }),
        (async () => {
          let lastErr: string = "";
          for (let attempt = 1; attempt <= 2; attempt++) {
            try { return await generateMiniMaxMusic({ prompt: musicPrompt }); } catch (e: any) { lastErr = e.message; }
          }
          throw new Error(`Music failed twice: ${lastErr}`);
        })(),
        voiceId && narrationText && isOpenAITtsConfigured()
          ? generateOpenAITts({ text: narrationText, voice: voiceId as any })
          : Promise.resolve(null),
      ]);

      if (slideResults.status === "rejected") return refundAndAbort(502, `Slideshow render failed: ${slideResults.reason?.message || "unknown"}`);
      if (fantasyResult.status === "rejected") return refundAndAbort(502, `Fantasy clip failed: ${fantasyResult.reason?.message || "unknown"}`);
      if (musicResult.status === "rejected") return refundAndAbort(502, `Music render failed: ${musicResult.reason?.message || "unknown"}`);
      if (voiceId && ttsResult.status === "rejected") {
        const reason = ttsResult.reason instanceof OpenAITtsUnavailableError ? "narration provider offline" : (ttsResult.reason?.message || "unknown");
        return refundAndAbort(502, `Narration failed: ${reason}`);
      }

      // ── Re-host all assets to Cloudinary (best-effort) ───────────────────
      const slideClipRaw = slideResults.value;
      const fantasyRaw = fantasyResult.value;
      const musicRaw = musicResult.value;
      const ttsRaw = ttsResult.status === "fulfilled" ? ttsResult.value : null;

      const slideRehosted = await Promise.all(
        slideClipRaw.map((r) => reHost(r.videoUrl, "video", "guber-studio-v2-listing-slide"))
      );
      const fantasyRehosted = await reHost(fantasyRaw.videoUrl, "video", "guber-studio-v2-listing-fantasy");
      const musicRehosted = await reHost(musicRaw.audioUrl, "video", "guber-studio-v2-listing-music");
      const ttsRehosted = ttsRaw ? await reHost(ttsRaw.dataUrl, "video", "guber-studio-v2-listing-narration") : null;

      // ── Persist session files ─────────────────────────────────────────────
      const baseMeta = { toolKey: TOOL_KEY, creditsCost, listingId, title, musicGenre, voiceId };

      const slideFiles = await Promise.all(slideRehosted.map((reh, i) =>
        storage.addStudioSessionFile({
          sessionId: session.id, userId,
          fileType: "output_video",
          providerUrl: reh.url,
          cloudinaryPublicId: reh.publicId,
          resourceType: "video",
          meta: { ...baseMeta, kind: "listing_slide", index: i, prompt: slidePrompt, providerJobId: slideClipRaw[i].jobId },
        })
      ));

      const fantasyFile = await storage.addStudioSessionFile({
        sessionId: session.id, userId,
        fileType: "output_video",
        providerUrl: fantasyRehosted.url,
        cloudinaryPublicId: fantasyRehosted.publicId,
        resourceType: "video",
        meta: { ...baseMeta, kind: "listing_fantasy", prompt: fantasyPrompt, providerJobId: fantasyRaw.jobId },
      });

      const musicFile = await storage.addStudioSessionFile({
        sessionId: session.id, userId,
        fileType: "output_audio",
        providerUrl: musicRehosted.url,
        cloudinaryPublicId: musicRehosted.publicId,
        resourceType: "video",
        meta: { ...baseMeta, kind: "listing_music", prompt: musicPrompt, providerJobId: musicRaw.jobId },
      });

      const narrationFile = ttsRehosted
        ? await storage.addStudioSessionFile({
            sessionId: session.id, userId,
            fileType: "output_audio",
            providerUrl: ttsRehosted.url,
            cloudinaryPublicId: ttsRehosted.publicId,
            resourceType: "video",
            meta: { ...baseMeta, kind: "listing_narration", voiceId },
          })
        : null;

      listingCleanup.clear();

      await storage.touchStudioSession(session.id);
      await storage.logStudioGeneration({
        userId, sessionId: session.id, toolKey: TOOL_KEY,
        prompt: slidePrompt.slice(0, 500), creditsCost,
        durationSeconds: 5, providerJobId: slideClipRaw[0]?.jobId ?? null, status: "succeeded",
        errorReason: null,
      });

      res.json({ slideClips: slideFiles, fantasyFile, musicFile, narrationFile, balance: newBalance });

    } catch (err: any) {
      console.error("[GUBER][studio][listing-video] unexpected:", err);
      let refundedBalance: number | null = null;
      if (creditsDebited > 0) {
        try { refundedBalance = await storage.incrementStudioCredits(userId, creditsDebited); } catch {}
        await cleanupCloudinaryAssets();
        try {
          await storage.logStudioGeneration({
            userId, sessionId: postDebitSessionId ?? 0, toolKey: TOOL_KEY,
            prompt: postDebitPrompt.slice(0, 500), creditsCost: creditsDebited,
            durationSeconds: null, providerJobId: null, status: "refunded",
            errorReason: `unexpected: ${(err.message || "unknown").slice(0, 480)}`,
          });
        } catch {}
      }
      const note = creditsDebited > 0 ? "Generation failed and your credits were returned." : "Unexpected error";
      res.status(500).json({ message: `${note} ${err.message || ""}`.trim(), balance: refundedBalance });
    }
  });

  // ── Promo Clip: 5-second text-to-video promo + music ─────────────────────
  // POST /api/studio/generate/promo-clip
  // Body: { name, tagline, description?, musicGenre }
  // Cost: 35 credits (wan_motion_5s 30 + minimax_music 5). No photo required.
  app.post("/api/studio/generate/promo-clip", requireAuth, async (req: Request, res: Response) => {
    const userId = req.session.userId!;
    let creditsDebited = 0;
    let postDebitSessionId: number | null = null;
    const TOOL_KEY = "promo_clip";
    const CREDITS_COST = 35;

    const MUSIC_GENRE_PROMPTS: Record<string, string> = {
      luxury:   "Cinematic luxury orchestral background music, smooth and elegant, premium advertisement",
      upbeat:   "Upbeat energetic background music, modern commercial vibe, positive energy",
      chill:    "Chill lofi background music, warm relaxing vibes, mellow",
      dramatic: "Epic dramatic cinematic background music, powerful and inspiring",
      romantic: "Romantic warm background music, emotional and heartfelt, soft piano",
      hype:     "Urban hype background music, modern trap beats, street energy, bold",
    };

    const { createCloudinaryCleanup } = await import("./studio/cloudinary-cleanup");
    let promoCleanup = createCloudinaryCleanup(null);
    const cleanupCloudinaryAssets = async () => { await promoCleanup.cleanup("promo-clip"); };

    try {
      const name = typeof req.body?.name === "string" ? req.body.name.trim().slice(0, 60) : "";
      const tagline = typeof req.body?.tagline === "string" ? req.body.tagline.trim().slice(0, 80) : "";
      const description = typeof req.body?.description === "string" ? req.body.description.trim().slice(0, 200) : "";
      const musicGenre = typeof req.body?.musicGenre === "string" ? req.body.musicGenre : "upbeat";

      if (!name) return res.status(400).json({ message: "name is required." });
      if (!tagline) return res.status(400).json({ message: "tagline is required." });

      const session = await ensureStudioSession(userId);

      // Auto-seed promo_clip pricing row on first use.
      const { studioModelPricing: studioModelPricingTable } = await import("../shared/schema");
      await db.insert(studioModelPricingTable).values({
        toolKey: TOOL_KEY,
        label: "Promo Clip",
        description: "5-second cinematic text-to-video promo with matching music.",
        providerEndpoint: "fal-ai/wan-motion",
        creditsCost: CREDITS_COST,
        durationSeconds: 5,
        active: true,
      }).onConflictDoNothing();

      const newBalance = await storage.decrementStudioCredits(userId, CREDITS_COST);
      if (newBalance === null) {
        return res.status(402).json({ message: "Not enough Studio credits. Buy a credit pack to keep creating." });
      }
      creditsDebited = CREDITS_COST;
      postDebitSessionId = session.id;

      let cloudinary: any = null;
      try {
        if (process.env.CLOUDINARY_CLOUD_NAME) cloudinary = (await import("./cloudinary.js")).default;
      } catch {}
      promoCleanup = createCloudinaryCleanup(cloudinary);

      const reHost = async (url: string, resourceType: "video" | "image", folder: string): Promise<{ url: string; publicId: string | null }> => {
        if (!cloudinary) return { url, publicId: null };
        try {
          const up = await cloudinary.uploader.upload(url, { resource_type: resourceType === "image" ? "image" : "video", folder });
          promoCleanup.track(up.public_id, resourceType === "image" ? "image" : "video");
          return { url: up.secure_url, publicId: up.public_id };
        } catch (err: any) {
          console.warn(`[GUBER][studio][promo-clip] cloudinary re-host failed: ${err.message}`);
          return { url, publicId: null };
        }
      };

      const videoPrompt = [
        `Cinematic 5-second promo for "${name}".`,
        `Tagline: "${tagline}".`,
        description ? `${description}.` : "",
        "Bold and eye-catching, dynamic motion graphics, professional commercial aesthetic, social media advertisement, dramatic lighting.",
      ].filter(Boolean).join(" ");

      const musicPrompt = MUSIC_GENRE_PROMPTS[musicGenre] ?? MUSIC_GENRE_PROMPTS["upbeat"];

      const refundAndAbort = async (httpStatus: number, message: string) => {
        await cleanupCloudinaryAssets();
        const refunded = await storage.incrementStudioCredits(userId, CREDITS_COST);
        await storage.logStudioGeneration({
          userId, sessionId: session.id, toolKey: TOOL_KEY,
          prompt: videoPrompt.slice(0, 500), creditsCost: CREDITS_COST,
          durationSeconds: 5, providerJobId: null, status: "refunded",
          errorReason: message.slice(0, 500),
        });
        return res.status(httpStatus).json({ message: `Generation failed and your credits were returned: ${message}`, balance: refunded });
      };

      const { generateWanMotion, generateMiniMaxMusic } = await import("./fal");

      // Run video + music in parallel.
      const [videoResult, musicResult] = await Promise.allSettled([
        generateWanMotion({ prompt: videoPrompt, durationSeconds: 5 }),
        (async () => {
          let lastErr = "";
          for (let attempt = 1; attempt <= 2; attempt++) {
            try { return await generateMiniMaxMusic({ prompt: musicPrompt }); } catch (e: any) { lastErr = e.message; }
          }
          throw new Error(`Music failed twice: ${lastErr}`);
        })(),
      ]);

      if (videoResult.status === "rejected") return refundAndAbort(502, `Video render failed: ${videoResult.reason?.message || "unknown"}`);
      if (musicResult.status === "rejected") return refundAndAbort(502, `Music render failed: ${musicResult.reason?.message || "unknown"}`);

      const videoRehosted = await reHost(videoResult.value.videoUrl, "video", "guber-studio-v2-promo-clip");
      const musicRehosted = await reHost(musicResult.value.audioUrl, "video", "guber-studio-v2-promo-music");

      const baseMeta = { toolKey: TOOL_KEY, creditsCost: CREDITS_COST, name, tagline, musicGenre };

      const videoFile = await storage.addStudioSessionFile({
        sessionId: session.id, userId,
        fileType: "output_video",
        providerUrl: videoRehosted.url,
        cloudinaryPublicId: videoRehosted.publicId,
        resourceType: "video",
        meta: { ...baseMeta, kind: "promo_clip_video", prompt: videoPrompt, providerJobId: videoResult.value.jobId },
      });
      const musicFile = await storage.addStudioSessionFile({
        sessionId: session.id, userId,
        fileType: "output_audio",
        providerUrl: musicRehosted.url,
        cloudinaryPublicId: musicRehosted.publicId,
        resourceType: "video",
        meta: { ...baseMeta, kind: "promo_clip_music", prompt: musicPrompt, providerJobId: musicResult.value.jobId },
      });

      promoCleanup.clear();

      await storage.touchStudioSession(session.id);
      await storage.logStudioGeneration({
        userId, sessionId: session.id, toolKey: TOOL_KEY,
        prompt: videoPrompt.slice(0, 500), creditsCost: CREDITS_COST,
        durationSeconds: 5, providerJobId: videoResult.value.jobId, status: "succeeded",
        errorReason: null,
      });

      res.json({ videoFile, musicFile, balance: newBalance });

    } catch (err: any) {
      console.error("[GUBER][studio][promo-clip] unexpected:", err);
      let refundedBalance: number | null = null;
      if (creditsDebited > 0) {
        try { refundedBalance = await storage.incrementStudioCredits(userId, creditsDebited); } catch {}
        await cleanupCloudinaryAssets();
        try {
          await storage.logStudioGeneration({
            userId, sessionId: postDebitSessionId ?? 0, toolKey: TOOL_KEY,
            prompt: "", creditsCost: creditsDebited,
            durationSeconds: null, providerJobId: null, status: "refunded",
            errorReason: `unexpected: ${(err.message || "unknown").slice(0, 480)}`,
          });
        } catch {}
      }
      const note = creditsDebited > 0 ? "Generation failed and your credits were returned." : "Unexpected error";
      res.status(500).json({ message: `${note} ${err.message || ""}`.trim(), balance: refundedBalance });
    }
  });

  // ── GUBER AI Director ──────────────────────────────────────────────────────
  // POST /api/studio/generate/ai-director
  // Body: { category, businessName, tagline, description?, cta?, durationTierId? }
  // Credits scale by tier: short=200, standard=320, long=560, extended=1160, feature=2240.
  // Deducts credits upfront, kicks off async assembly job, returns { jobId }.
  // Poll GET /api/studio/director/jobs/:jobId for status.
  app.post("/api/studio/generate/ai-director", requireAuth, async (req: Request, res: Response) => {
    const userId = req.session.userId!;

    const { DURATION_TIERS, createDirectorJob, runDirectorJob } = await import("./studio/ai-director");

    const VALID_CATEGORIES = [
      "home_services", "auto", "beauty", "moving",
      "events", "fitness", "food", "general",
    ] as const;

    const category = typeof req.body?.category === "string" ? req.body.category : "";
    const businessName = typeof req.body?.businessName === "string" ? req.body.businessName.trim().slice(0, 50) : "";
    const tagline = typeof req.body?.tagline === "string" ? req.body.tagline.trim().slice(0, 70) : "";
    const description = typeof req.body?.description === "string" ? req.body.description.trim().slice(0, 200) : "";
    const cta = typeof req.body?.cta === "string" ? req.body.cta.trim().slice(0, 60) : "";
    const durationTierId = typeof req.body?.durationTierId === "string" ? req.body.durationTierId : "short";

    if (!VALID_CATEGORIES.includes(category as any))
      return res.status(400).json({ message: "Invalid category." });
    if (!businessName) return res.status(400).json({ message: "businessName is required." });
    if (!tagline) return res.status(400).json({ message: "tagline is required." });

    const tier = DURATION_TIERS[durationTierId as keyof typeof DURATION_TIERS];
    if (!tier) return res.status(400).json({ message: "Invalid durationTierId." });

    const CREDITS_COST = tier.credits;
    const nClips = tier.clips;

    // Deduct credits upfront
    const newBalance = await storage.decrementStudioCredits(userId, CREDITS_COST);
    if (newBalance === null)
      return res.status(402).json({ message: "Not enough Studio credits. Buy a credit pack to keep creating." });

    // Ensure an open session exists (function is in scope within registerRoutes)
    const session = await ensureStudioSession(userId);

    const jobId = `dir_${userId}_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
    const job = createDirectorJob(jobId, userId, CREDITS_COST);

    // Fire-and-forget — credits already debited, refund happens inside job on failure
    runDirectorJob(
      job,
      { category: category as any, businessName, tagline, description, cta, nClips },
      storage,
      db,
      session.id,
    ).catch((err) => {
      console.error("[ai-director] unhandled job error:", err);
    });

    res.json({ jobId, status: "pending", tier: durationTierId, credits: CREDITS_COST });
  });

  // GET /api/studio/director/jobs/:jobId
  // Returns the current status, stage text, and outputUrl when complete.
  app.get("/api/studio/director/jobs/:jobId", requireAuth, async (req: Request, res: Response) => {
    const { getDirectorJob } = await import("./studio/ai-director");
    const job = getDirectorJob(String(req.params.jobId));
    if (!job) return res.status(404).json({ message: "Job not found or expired." });
    if (job.userId !== req.session.userId!)
      return res.status(403).json({ message: "Forbidden." });
    res.json({
      jobId: job.jobId,
      status: job.status,
      stage: job.stage,
      outputUrl: job.outputUrl,
      error: job.error,
    });
  });

  app.post("/api/stripe/trust-box-checkout", requireAuth, async (req: Request, res: Response) => {
    try {
      const user = await storage.getUser(req.session.userId!);
      if (!user) return res.status(401).json({ message: "User not found" });
      if (user.trustBoxPurchased && user.trustBoxSubscriptionId) {
        return res.status(400).json({ message: "Trust Box subscription already active" });
      }

      const host = req.get("host") || "localhost:5000";
      const protocol = req.get("x-forwarded-proto") || "http";
      const baseUrl = `${protocol}://${host}`;

      if (!TRUST_BOX_PAYROLL_PRICE_ID) {
        return res.status(503).json({ message: "Trust Box checkout not configured. Contact support@guberapp.com." });
      }

      const stripeSession = await stripe.checkout.sessions.create({
        payment_method_types: ["card"],
        customer_email: user.email,
        line_items: [{ price: TRUST_BOX_PAYROLL_PRICE_ID, quantity: 1 }],
        mode: "subscription",
        success_url: `${baseUrl}/ai-or-not?trustbox=success`,
        cancel_url: `${baseUrl}/ai-or-not`,
        subscription_data: {
          metadata: { userId: String(user.id), userEmail: user.email, type: "trust_box" },
        },
        metadata: { userId: String(user.id), userEmail: user.email, type: "trust_box" },
      });

      res.json({ checkoutUrl: stripeSession.url });
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  // CORS-accessible checkout — used when the AI-or-Not iframe calls directly
  // (cross-origin, so session cookie is blocked). Authenticated via HMAC sig.
  const AI_OR_NOT_ORIGIN = "https://ai-or-not-1.replit.app";
  const embedCors = (req: Request, res: Response) => {
    const origin = req.get("origin") || "";
    if (origin === AI_OR_NOT_ORIGIN) {
      res.setHeader("Access-Control-Allow-Origin", AI_OR_NOT_ORIGIN);
      res.setHeader("Access-Control-Allow-Methods", "POST, OPTIONS");
      res.setHeader("Access-Control-Allow-Headers", "Content-Type");
      res.setHeader("Access-Control-Allow-Credentials", "false");
    }
  };

  app.options("/api/stripe/trust-box-checkout-embed", (req: Request, res: Response) => {
    embedCors(req, res);
    res.sendStatus(204);
  });

  app.post("/api/stripe/trust-box-checkout-embed", async (req: Request, res: Response) => {
    embedCors(req, res);
    try {
      const { uid, sig, returnUrl } = req.body;
      if (!uid || !sig) return res.status(400).json({ message: "uid and sig required" });

      const secret = process.env.GUBER_SHARED_SECRET;
      if (!secret) return res.status(503).json({ message: "Not configured" });

      const user = await storage.getUser(parseInt(String(uid), 10));
      if (!user) return res.status(404).json({ message: "User not found" });

      const isOG  = user.day1OG ? "1" : "0";
      const trustBox = (user as any).trustBoxPurchased ? "1" : "0";
      const credits = String((user as any).aiOrNotCredits ?? 0);
      const payload = `${uid}${isOG}${trustBox}${credits}`;
      const expected = createHmac("sha256", secret).update(payload).digest("hex");
      if (sig !== expected) return res.status(403).json({ message: "Invalid signature" });

      if ((user as any).trustBoxPurchased && user.trustBoxSubscriptionId) {
        return res.status(400).json({ message: "Trust Box subscription already active" });
      }

      const baseUrl = returnUrl || "https://guberapp.app";

      if (!TRUST_BOX_PAYROLL_PRICE_ID) {
        return res.status(503).json({ message: "Trust Box checkout not configured. Contact support@guberapp.com." });
      }

      const stripeSession = await stripe.checkout.sessions.create({
        payment_method_types: ["card"],
        customer_email: user.email,
        line_items: [{ price: TRUST_BOX_PAYROLL_PRICE_ID, quantity: 1 }],
        mode: "subscription",
        success_url: `${baseUrl}/ai-or-not?trustbox=success`,
        cancel_url: `${baseUrl}/ai-or-not`,
        subscription_data: {
          metadata: { userId: String(user.id), userEmail: user.email, type: "trust_box" },
        },
        metadata: { userId: String(user.id), userEmail: user.email, type: "trust_box" },
      });

      res.json({ checkoutUrl: stripeSession.url });
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  app.post("/api/stripe/cancel-trust-box", requireAuth, async (req: Request, res: Response) => {
    try {
      const user = await storage.getUser(req.session.userId!);
      if (!user) return res.status(401).json({ message: "User not found" });
      if (!user.trustBoxSubscriptionId) return res.status(400).json({ message: "No active Trust Box subscription" });

      try {
        await stripe.subscriptions.cancel(user.trustBoxSubscriptionId);
      } catch (cancelErr: any) {
        // If not found on payroll account, try the old account (legacy members)
        if (cancelErr?.statusCode === 404 || cancelErr?.raw?.code === "resource_missing") {
          await stripeMain.subscriptions.cancel(user.trustBoxSubscriptionId);
        } else {
          throw cancelErr;
        }
      }
      await storage.updateUser(user.id, { trustBoxPurchased: false, trustBoxSubscriptionId: null });
      await storage.createAuditLog({ userId: user.id, action: "trust_box_cancelled", details: `Trust Box subscription cancelled by user. Sub: ${user.trustBoxSubscriptionId}` });
      res.json({ message: "Trust Box subscription cancelled" });
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  app.post("/api/stripe/confirm-trust-box", requireAuth, async (req: Request, res: Response) => {
    try {
      const { sessionId } = req.body;
      const stripeSession = await stripe.checkout.sessions.retrieve(sessionId);

      const isTrustBox = stripeSession.metadata?.type === "trust_box";
      const isPaidOrActive = stripeSession.payment_status === "paid" || stripeSession.status === "complete";
      if (isTrustBox && isPaidOrActive) {
        const userId = parseInt(stripeSession.metadata!.userId);
        if (userId !== req.session.userId) return res.status(403).json({ message: "Session mismatch" });

        const existing = await storage.getUser(userId);
        const subscriptionId = stripeSession.subscription as string | undefined;
        if (!existing?.trustBoxPurchased) {
          await storage.updateUser(userId, {
            trustBoxPurchased: true,
            ...(subscriptionId ? { trustBoxSubscriptionId: subscriptionId } : {}),
          });
          await storage.createNotification({
            userId,
            title: "Trust Box Active!",
            body: "Your AI or Not premium subscription is live. $4.99/month.",
            type: "system",
          });
        }

        const user = await storage.getUser(userId);
        res.json(sanitizeUser(user!));
      } else {
        res.status(400).json({ message: "Subscription not completed" });
      }
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

